import{_ as e,o as r,c as s,a2 as o}from"./chunks/framework.BS3ZfcoS.js";const u=JSON.parse('{"title":"职场被穷养","description":"","frontmatter":{"title":"职场被穷养","author":"","collection":"职场成长","series_order":4,"total_chars":1582},"headers":[],"relativePath":"career/workplace-poor.md","filePath":"career/workplace-poor.md"}'),t={name:"career/workplace-poor.md"};function h(n,a,l,i,d,p){return r(),s("div",null,[...a[0]||(a[0]=[o('<h2 id="s-365" tabindex="-1">职场被穷养系列 <a class="header-anchor" href="#s-365" aria-label="Permalink to &quot;职场被穷养系列 {#s-365}&quot;">​</a></h2><p>共6个视频</p><h3 id="s-366" tabindex="-1">职场被穷养，该如何投资自己？普通人如何改变命运？ <a class="header-anchor" href="#s-366" aria-label="Permalink to &quot;职场被穷养，该如何投资自己？普通人如何改变命运？ {#s-366}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-367" tabindex="-1">1. 心理贫穷比物质贫穷更致命——物质上的穷只穷一阵子，心理上的穷会穷一辈子 <a class="header-anchor" href="#s-367" aria-label="Permalink to &quot;1. 心理贫穷比物质贫穷更致命——物质上的穷只穷一阵子，心理上的穷会穷一辈子 {#s-367}&quot;">​</a></h4><p>**2. **稀缺心态四大问题：管窥效应（短视）、借用（透支未来）、缺乏余闲（无抗风险能力）、带宽不足（精神内耗导致决策变差）</p><h4 id="s-368" tabindex="-1">3. 培养积极注意力偏好：把注意力放在事情好的一面，像滚雪球一样越滚越大 <a class="header-anchor" href="#s-368" aria-label="Permalink to &quot;3. 培养积极注意力偏好：把注意力放在事情好的一面，像滚雪球一样越滚越大 {#s-368}&quot;">​</a></h4><h4 id="s-369" tabindex="-1">4. 可以暂时待在穷养型环境，但绝不可有穷养心态，要主动搭建富养环境 <a class="header-anchor" href="#s-369" aria-label="Permalink to &quot;4. 可以暂时待在穷养型环境，但绝不可有穷养心态，要主动搭建富养环境 {#s-369}&quot;">​</a></h4><p>**5. **搭建知识与信息富养环境：信息差是出身普通者最大劣势，要花钱学习、参加行业活动、听播客补认知差</p><p><strong>金句</strong></p><p><em>「物质上的穷可能只会让你穷一阵子，但心理上的穷会让你穷一辈子」</em></p><p><strong>行动指南</strong></p><p>培养积极注意力偏好，每年花钱学习课程参加行业活动，搭建信息富养环境</p><h3 id="s-370" tabindex="-1">原来真的会有公司花两年100w培养新员工 <a class="header-anchor" href="#s-370" aria-label="Permalink to &quot;原来真的会有公司花两年100w培养新员工 {#s-370}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-371" tabindex="-1">1. 富养型公司愿在管培生身上投入百万级培养成本 <a class="header-anchor" href="#s-371" aria-label="Permalink to &quot;1. 富养型公司愿在管培生身上投入百万级培养成本 {#s-371}&quot;">​</a></h4><h4 id="s-372" tabindex="-1">2. 公司算的是长期价值——每位员工创造的价值远超百万 <a class="header-anchor" href="#s-372" aria-label="Permalink to &quot;2. 公司算的是长期价值——每位员工创造的价值远超百万 {#s-372}&quot;">​</a></h4><h4 id="s-373" tabindex="-1">3. 富养型职场为员工制定成长地图和阶段课程库，像升级打怪一样推进 <a class="header-anchor" href="#s-373" aria-label="Permalink to &quot;3. 富养型职场为员工制定成长地图和阶段课程库，像升级打怪一样推进 {#s-373}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「每一位同事真正给公司带来的价值，长期来说远远超过百万」</em></p><p><strong>行动指南</strong></p><p>识别并争取富养型职场环境，珍惜有系统培养机制的公司</p><h3 id="s-374" tabindex="-1">原来真的会有公司花两年100w培养新员工（完整版） <a class="header-anchor" href="#s-374" aria-label="Permalink to &quot;原来真的会有公司花两年100w培养新员工（完整版） {#s-374}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-375" tabindex="-1">1. 职场是为自己选择的第二个原生家庭，分为富养型和穷养型 <a class="header-anchor" href="#s-375" aria-label="Permalink to &quot;1. 职场是为自己选择的第二个原生家庭，分为富养型和穷养型 {#s-375}&quot;">​</a></h4><p>**2. **穷养型环境三大困扰：不敢请教（像被领养的小孩）、自卑（自动PUA自己）、方向迷茫</p><p>**3. **富养型环境特征：Mentor带教、系统化人才培训、外部教练助推、全球转岗机会</p><h4 id="s-376" tabindex="-1">4. 职场前期一定要有人往上提你，没有人的话很难走远 <a class="header-anchor" href="#s-376" aria-label="Permalink to &quot;4. 职场前期一定要有人往上提你，没有人的话很难走远 {#s-376}&quot;">​</a></h4><h4 id="s-377" tabindex="-1">5. 很多公司要&quot;自驱力强&quot;的人，实际是不管你——对新人要求不合理 <a class="header-anchor" href="#s-377" aria-label="Permalink to &quot;5. 很多公司要&quot;自驱力强&quot;的人，实际是不管你——对新人要求不合理 {#s-377}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「你在职场上有好多时候，不是你做的不够好，而是因为你不够老」</em></p><p><strong>行动指南</strong></p><p>识别自己所在职场环境类型，主动寻求Mentor和成长资源</p><h3 id="s-378" tabindex="-1">职场被穷养，该如何投资自己？普通人如何职场通关？（三） <a class="header-anchor" href="#s-378" aria-label="Permalink to &quot;职场被穷养，该如何投资自己？普通人如何职场通关？（三） {#s-378}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-379" tabindex="-1">1. 在探索机会上富养自己：小公司灵活优势——容易成为头部，岗位变迁灵活 <a class="header-anchor" href="#s-379" aria-label="Permalink to &quot;1. 在探索机会上富养自己：小公司灵活优势——容易成为头部，岗位变迁灵活 {#s-379}&quot;">​</a></h4><h4 id="s-380" tabindex="-1">2. 多岗位尝试能深刻认识自己喜欢什么、不擅长什么，积累多元业务视角 <a class="header-anchor" href="#s-380" aria-label="Permalink to &quot;2. 多岗位尝试能深刻认识自己喜欢什么、不擅长什么，积累多元业务视角 {#s-380}&quot;">​</a></h4><h4 id="s-381" tabindex="-1">3. 思考搭建商业系统：你所在的小公司很可能就是你长大后的样子 <a class="header-anchor" href="#s-381" aria-label="Permalink to &quot;3. 思考搭建商业系统：你所在的小公司很可能就是你长大后的样子 {#s-381}&quot;">​</a></h4><h4 id="s-382" tabindex="-1">4. 小公司商业系统因为够小，可以深刻理解甚至复制它 <a class="header-anchor" href="#s-382" aria-label="Permalink to &quot;4. 小公司商业系统因为够小，可以深刻理解甚至复制它 {#s-382}&quot;">​</a></h4><h4 id="s-383" tabindex="-1">5. 利他思维：越弱小越要主动为别人提供价值，感恩之心激发世界善意 <a class="header-anchor" href="#s-383" aria-label="Permalink to &quot;5. 利他思维：越弱小越要主动为别人提供价值，感恩之心激发世界善意 {#s-383}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「当你怀揣着感恩之心去面对世界，你会激发这个世界给你的善意」</em></p><p><strong>行动指南</strong></p><p>主动承担不同岗位工作理解业务全貌，观察并理解公司商业系统，主动为他人提供价值</p><h3 id="s-384" tabindex="-1">职场被穷养，该如何投资自己？普通人如何职场通关？（二） <a class="header-anchor" href="#s-384" aria-label="Permalink to &quot;职场被穷养，该如何投资自己？普通人如何职场通关？（二） {#s-384}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-385" tabindex="-1">1. 培养积极注意力偏好：出身不好的人尤其重要，看过去要找到力量而非只看缺陷 <a class="header-anchor" href="#s-385" aria-label="Permalink to &quot;1. 培养积极注意力偏好：出身不好的人尤其重要，看过去要找到力量而非只看缺陷 {#s-385}&quot;">​</a></h4><h4 id="s-386" tabindex="-1">2. 遇到挫折默念&quot;所发生一切皆有助于我&quot;，用积极视角理解上天想教会你什么 <a class="header-anchor" href="#s-386" aria-label="Permalink to &quot;2. 遇到挫折默念&quot;所发生一切皆有助于我&quot;，用积极视角理解上天想教会你什么 {#s-386}&quot;">​</a></h4><p>**3. **搭建知识与信息富养环境：信息要新（前沿动态+高价值机会），知识要体系化（方法论）</p><h4 id="s-387" tabindex="-1">4. 花钱学习课程、参加行业活动、付费找优化师改简历、听商业财经播客补信息差 <a class="header-anchor" href="#s-387" aria-label="Permalink to &quot;4. 花钱学习课程、参加行业活动、付费找优化师改简历、听商业财经播客补信息差 {#s-387}&quot;">​</a></h4><h4 id="s-388" tabindex="-1">5. 把听到的信息结合思考变成面试谈资，让面试官觉得你认知水平高 <a class="header-anchor" href="#s-388" aria-label="Permalink to &quot;5. 把听到的信息结合思考变成面试谈资，让面试官觉得你认知水平高 {#s-388}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「人是不可能赚到自己认知以外的钱的」</em></p><p><strong>行动指南</strong></p><p>每年花钱学习课程和参加行业活动，面试前听行业播客把信息变谈资</p><h3 id="s-389" tabindex="-1">职场被穷养，该如何投资自己？普通人如何职场通关？（导读） <a class="header-anchor" href="#s-389" aria-label="Permalink to &quot;职场被穷养，该如何投资自己？普通人如何职场通关？（导读） {#s-389}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-390" tabindex="-1">1. 职场是为自己寻找的第二个原生家庭 <a class="header-anchor" href="#s-390" aria-label="Permalink to &quot;1. 职场是为自己寻找的第二个原生家庭 {#s-390}&quot;">​</a></h4><h4 id="s-391" tabindex="-1">2. 心理贫穷比物质贫穷更致命 <a class="header-anchor" href="#s-391" aria-label="Permalink to &quot;2. 心理贫穷比物质贫穷更致命 {#s-391}&quot;">​</a></h4><h4 id="s-392" tabindex="-1">3. 稀缺心态四大问题：管窥效应、借用、缺乏余闲、带宽不足 <a class="header-anchor" href="#s-392" aria-label="Permalink to &quot;3. 稀缺心态四大问题：管窥效应、借用、缺乏余闲、带宽不足 {#s-392}&quot;">​</a></h4><h4 id="s-393" tabindex="-1">4. 核心立场：可以暂时待在穷养型环境，但绝不可有穷养心态 <a class="header-anchor" href="#s-393" aria-label="Permalink to &quot;4. 核心立场：可以暂时待在穷养型环境，但绝不可有穷养心态 {#s-393}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「我可以暂时性地待在一个穷养型的环境里，但是绝不可以有穷养心态」</em></p><p><strong>行动指南</strong></p><p>正视现状，拒绝穷养心态，主动搭建富养环境</p>',65)])])}const q=e(t,[["render",h]]);export{u as __pageData,q as default};
